// Filter documents that need re-embedding
// These are documents in knowledge_documents that either:
// 1. Have no corresponding rows in document_embeddings with a non-'knowledge' collection
// 2. Were last embedded before the dual-write was enabled
const items = $input.all();
const docs = items[0]?.json?.data || items[0]?.json || [];

if (!Array.isArray(docs) || docs.length === 0) {
  return [{ json: { message: 'No documents to process', count: 0 } }];
}

// Return first 10 documents for processing (batch to avoid overload)
const batch = docs.slice(0, 10);
return batch.map(doc => ({ json: doc }));

const items = $input.all();
const results = items.map(item => ({
  document_id: item.json.data?.document_id || item.json.document_id || 'unknown',
  chunks: item.json.data?.chunks || 0,
  success: item.json.success !== false
}));
const succeeded = results.filter(r => r.success).length;
const failed = results.filter(r => !r.success).length;
return [{ json: { 
  message: 'Reembed sweep complete',
  processed: results.length, 
  succeeded, 
  failed,
  results 
} }];
